import{_ as r}from"./chunks/ScaleDisplay.vue_vue_type_script_setup_true_lang.BXLvQvzL.js";import{C as e,o as l,c as n,ag as a,E as o,w as i}from"./chunks/framework.DLbVeA01.js";import"./chunks/Piano.QhCkvqJz.js";const q=JSON.parse('{"title":"教会调式 Church Modes","description":"","frontmatter":{},"headers":[],"relativePath":"scales/modes.md","filePath":"scales/modes.md"}'),s={name:"scales/modes.md"},g=Object.assign(s,{setup(h){return(u,t)=>{const d=e("ClientOnly");return l(),n("div",null,[t[0]||(t[0]=a('<h1 id="教会调式-church-modes" tabindex="-1">教会调式 Church Modes <a class="header-anchor" href="#教会调式-church-modes" aria-label="Permalink to &quot;教会调式 Church Modes&quot;">​</a></h1><p>教会调式是中世纪音乐的遗产，每种调式都有独特的情感色彩。它们都可以理解为<strong>从大调音阶的不同音级开始</strong>。</p><h2 id="七种调式" tabindex="-1">七种调式 <a class="header-anchor" href="#七种调式" aria-label="Permalink to &quot;七种调式&quot;">​</a></h2><p>以 C 大调的音符为基础（全部白键）：</p><table tabindex="0"><thead><tr><th>调式</th><th>起始音</th><th>音符</th><th>情感色彩</th></tr></thead><tbody><tr><td>Ionian (伊奥尼亚)</td><td>C</td><td>C-D-E-F-G-A-B</td><td>= 大调，明亮稳定</td></tr><tr><td>Dorian (多利亚)</td><td>D</td><td>D-E-F-G-A-B-C</td><td>小调但更明亮，爵士</td></tr><tr><td>Phrygian (弗里几亚)</td><td>E</td><td>E-F-G-A-B-C-D</td><td>异域，西班牙/弗拉门戈</td></tr><tr><td>Lydian (利底亚)</td><td>F</td><td>F-G-A-B-C-D-E</td><td>梦幻，飘浮感</td></tr><tr><td>Mixolydian (混合利底亚)</td><td>G</td><td>G-A-B-C-D-E-F</td><td>摇滚，布鲁斯</td></tr><tr><td>Aeolian (爱奥尼亚)</td><td>A</td><td>A-B-C-D-E-F-G</td><td>= 自然小调，忧郁</td></tr><tr><td>Locrian (洛克里亚)</td><td>B</td><td>B-C-D-E-F-G-A</td><td>极不稳定，几乎不用</td></tr></tbody></table><h2 id="如何理解调式" tabindex="-1">如何理解调式？ <a class="header-anchor" href="#如何理解调式" aria-label="Permalink to &quot;如何理解调式？&quot;">​</a></h2><p>最实用的方式是用<strong>和大调/小调的对比</strong>来记忆：</p><ul><li><strong>Dorian</strong> = 自然小调 + 升高第 6 音 → &quot;明亮的小调&quot;</li><li><strong>Phrygian</strong> = 自然小调 + 降低第 2 音 → &quot;异域的小调&quot;</li><li><strong>Lydian</strong> = 大调 + 升高第 4 音 → &quot;梦幻的大调&quot;</li><li><strong>Mixolydian</strong> = 大调 + 降低第 7 音 → &quot;摇滚的大调&quot;</li></ul>',8)),o(d,null,{default:i(()=>[o(r)]),_:1}),t[1]||(t[1]=a('<h2 id="调式在现代音乐中的应用" tabindex="-1">调式在现代音乐中的应用 <a class="header-anchor" href="#调式在现代音乐中的应用" aria-label="Permalink to &quot;调式在现代音乐中的应用&quot;">​</a></h2><ul><li><strong>Dorian</strong>: Miles Davis &quot;So What&quot;、Daft Punk &quot;Get Lucky&quot;</li><li><strong>Mixolydian</strong>: Beatles &quot;Norwegian Wood&quot;、大量摇滚乐</li><li><strong>Lydian</strong>: 电影配乐中的&quot;梦幻&quot;场景</li></ul><h2 id="相关主题" tabindex="-1">相关主题 <a class="header-anchor" href="#相关主题" aria-label="Permalink to &quot;相关主题&quot;">​</a></h2><ul><li><a href="/scales/pentatonic.html">五声音阶</a> — 更简单但同样重要的音阶</li><li><a href="/scales/major.html">大调音阶</a> — 调式的基础</li></ul>',4))])}}});export{q as __pageData,g as default};
